// =============================================================
// API 키 인증 및 복잡도 분석
// 메시지 길이와 키워드를 기반으로 적절한 모델을 선택
// =============================================================

const headers = $input.first().json.headers || {};
const body    = $input.first().json.body || {};

// API 키 인증
const expectedApiKey = $env.API_SECRET_KEY || 'n8n-ollama-api-key-2024';
const providedApiKey = headers['x-api-key'] || headers['X-API-Key'] || '';

if (providedApiKey !== expectedApiKey) {
  throw new Error('AUTH_FAILED: 유효하지 않은 API 키입니다.');
}

const message         = (body.message || '').trim();
const complexityHint  = (body.complexity_hint || 'auto').toLowerCase();
const sessionId       = body.session_id || `router_${Date.now()}`;

if (!message) {
  throw new Error('VALIDATION_ERROR: message 필드는 필수입니다.');
}

// -------------------------------------------------------
// 복잡도 자동 감지 로직
// complexityHint가 'auto'인 경우에만 자동 분석
// -------------------------------------------------------
let complexity;
let selectionReason;

if (complexityHint !== 'auto' && ['simple', 'medium', 'complex'].includes(complexityHint)) {
  // 사용자 지정 복잡도 사용
  complexity       = complexityHint;
  selectionReason  = `사용자 지정 복잡도: ${complexityHint}`;
} else {
  // 자동 감지: 메시지 길이 기반 1차 판단
  const wordCount   = message.split(/\s+/).length;
  const charCount   = message.length;

  // 복잡한 질문을 나타내는 키워드 목록
  const complexKeywords = [
    '분석', '비교', '설명', '작성', '구현', '설계', '아키텍처',
    'analyze', 'compare', 'explain', 'implement', 'design', 'architecture',
    '왜', '어떻게', '차이점', '장단점', 'why', 'how', 'difference',
    '코드', 'code', '알고리즘', 'algorithm', '최적화', 'optimize'
  ];

  // 단순 질문 키워드
  const simpleKeywords = [
    '안녕', '뭐야', '뭐에요', '뭔가요', 'hi', 'hello', '시간', 'time',
    '날씨', 'weather', '예', '아니오', 'yes', 'no'
  ];

  const lowerMessage     = message.toLowerCase();
  const hasComplexKw     = complexKeywords.some(kw => lowerMessage.includes(kw.toLowerCase()));
  const hasSimpleKw      = simpleKeywords.some(kw => lowerMessage.includes(kw.toLowerCase()));

  if (hasSimpleKw && !hasComplexKw && wordCount <= 10) {
    complexity      = 'simple';
    selectionReason = `단순 키워드 감지, 단어 수: ${wordCount}`;
  } else if (hasComplexKw || wordCount > 50 || charCount > 300) {
    complexity      = 'complex';
    selectionReason = `복잡 키워드 감지 또는 메시지 길이 초과 (단어: ${wordCount}, 글자: ${charCount})`;
  } else {
    complexity      = 'medium';
    selectionReason = `중간 복잡도 (단어: ${wordCount}, 글자: ${charCount})`;
  }
}

// 복잡도별 모델 매핑
const modelMap = {
  simple:  'llama3.2:1b',
  medium:  'llama3.2',
  complex: 'llama3.2:latest'
};

const selectedModel = modelMap[complexity];

return {
  message,
  sessionId,
  complexity,
  selectedModel,
  selectionReason,
  requestStartTime: Date.now(),
  requestId: `router_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`
};

// =============================================================
// 모든 모델 응답을 통합하여 최종 응답 생성
// 어떤 경로에서 오든 동일한 형식으로 포맷팅
// =============================================================

// 활성화된 입력 노드에서 응답 가져오기
const ollamaResponse = $input.first().json;
const analyzeData    = $('인증 및 복잡도 분석').first().json;

// 모델 응답 추출
const aiMessage  = ollamaResponse?.message?.content || ollamaResponse?.response || '응답 생성 실패';
const modelUsed  = ollamaResponse?.model || analyzeData.selectedModel;
const responseTime = Date.now() - analyzeData.requestStartTime;

return {
  requestId:       analyzeData.requestId,
  sessionId:       analyzeData.sessionId,
  userMessage:     analyzeData.message,
  aiMessage,
  modelUsed,
  complexity:      analyzeData.complexity,
  selectionReason: analyzeData.selectionReason,
  responseTime
};

// =============================================================
// 라우터 에러 처리
// 모델 로드 실패, 타임아웃 등 모델별 에러 처리
// =============================================================

const error        = $input.first().json.error || {};
const errorMessage = error.message || '모델 요청 중 오류가 발생했습니다.';

let statusCode = 500;
let errorCode  = 'MODEL_ERROR';

if (errorMessage.startsWith('AUTH_FAILED'))       { statusCode = 401; errorCode = 'UNAUTHORIZED'; }
else if (errorMessage.startsWith('VALIDATION'))   { statusCode = 400; errorCode = 'BAD_REQUEST'; }
else if (errorMessage.includes('model not found')) { statusCode = 503; errorCode = 'MODEL_NOT_FOUND'; }
else if (errorMessage.includes('timeout'))         { statusCode = 504; errorCode = 'GATEWAY_TIMEOUT'; }

return {
  errorResponse: JSON.stringify({
    success:   false,
    error:     errorCode,
    message:   '요청을 처리하는 중 오류가 발생했습니다. 잠시 후 다시 시도하세요.',
    detail:    errorMessage,
    timestamp: new Date().toISOString()
  }),
  statusCode
};
